 6→
 7→export type UpdateTaskResult = {
 8→  task_id: string;
 9→  status: string;
10→  updated: boolean;
11→};
12→
13→/** Port: update a task's status. Returns the result of the update. */
14→export type UpdateTaskPort = (
15→  taskId: string,
16→  status: string,
17→) => Promise<UpdateTaskResult>;
18→
19→/** Port: check whether a task exists in the workspace. */
20→export type TaskExistsPort = (taskId: string) => Promise<boolean>;
