206→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
207→  const result: Record<string, unknown> = {};
208→  for (const [key, value] of Object.entries(obj)) {
209→    if (value !== undefined) {
210→      result[key] = value;
211→    }
212→  }
213→  return result as Partial<T>;
214→}
