662→// ---------------------------------------------------------------------------
663→// rejectOrchestratorSession
664→// ---------------------------------------------------------------------------
665→
666→type RejectSessionInput = {
667→  surreal: Surreal;
668→  sessionId: string;
669→  feedback: string;
670→};
671→
672→export async function rejectOrchestratorSession(
673→  input: RejectSessionInput,
674→): Promise<RejectSessionResult> {
675→  const lookup = await lookupSession(input.surreal, input.sessionId);
676→  if (!lookup.ok) {
677→    return { ok: false, error: lookup.error };
678→  }
679→  const { session, record: sessionRecord, status } = lookup;
680→
681→  if (!REJECTABLE_STATUSES.has(status)) {
682→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
683→  }
684→
685→  // 1. Update session status to active (agent resumes work)
686→  await input.surreal.update(sessionRecord).merge({
687→    orchestrator_status: "active" as OrchestratorStatus,
688→    last_feedback: input.feedback,
689→  });
690→
691→  // 2. Return task to in_progress
692→  if (session.task_id) {
693→    await input.surreal.update(session.task_id).merge({
694→      status: "in_progress",
695→      updated_at: new Date(),
696→    });
697→  }
698→
699→  return {
700→    ok: true,
701→    value: {
702→      rejected: true,
703→      continuing: true,
704→    },
705→  };
706→}
