209→/** List architecture constraints, optionally scoped to a project */
210→export async function listProjectConstraints(input: {
211→  surreal: Surreal;
212→  workspaceRecord: RecordId<"workspace", string>;
213→  projectRecord?: RecordId<"project", string>;
214→  area?: string;
215→}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
216→  // Constraints come from two sources:
217→  // 1. Decisions marked as confirmed/contested (hard constraints)
218→  // 2. Observations with severity "conflict" or "warning"
219→
220→  const areaFilter = input.area ? `AND category = $area` : "";
221→  const projectFilter = input.projectRecord
222→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
223→    : "";
224→
225→  const query = `
226→    SELECT summary AS text, "decision" AS source_type, status, id, created_at
227→    FROM decision
228→    WHERE workspace = $workspace
229→      ${projectFilter}
230→      AND status IN ["confirmed", "contested"]
231→      ${areaFilter}
232→    ORDER BY created_at DESC LIMIT 30;
233→
234→    SELECT text, "observation" AS source_type, severity, id, created_at
235→    FROM observation
236→    WHERE workspace = $workspace
237→      AND status IN ["open", "acknowledged"]
238→      AND severity IN ["conflict", "warning"]
239→    ORDER BY created_at DESC LIMIT 20;
240→  `;
241→
242→  const results = await input.surreal
243→    .query<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
244→      query,
245→      {
246→        workspace: input.workspaceRecord,
247→        ...(input.projectRecord ? { project: input.projectRecord } : {}),
248→        ...(input.area ? { area: input.area } : {}),
249→      },
250→    )
251→    .collect<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
252→
253→  const [decisionRows, observationRows] = results;
254→
255→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
256→
257→  for (const d of decisionRows) {
258→    constraints.push({
259→      text: d.text,
260→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
261→      severity: "hard",
262→    });
263→  }
264→
265→  for (const o of observationRows) {
266→    constraints.push({
267→      text: o.text,
268→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
269→      severity: o.severity === "conflict" ? "hard" : "soft",
270→    });
271→  }
272→
273→  return constraints;
274→}
