291→    FROM decision
292→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
293→    ORDER BY updated_at DESC LIMIT 20;
294→
295→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
296→    FROM task
