 1→/**
 2→ * Pure function to determine which tasks need status updates based on push context.
 3→ *
 4→ * Step 03-01: Feature branch push -> set tasks to "done"
 5→ * Step 03-02: Default branch push -> set tasks to "completed"
 6→ */
 7→
 8→export type TaskStatusContext = {
 9→  taskId: string;
10→  currentStatus: string;
11→};
12→
13→export type TaskStatusUpdate = {
14→  taskId: string;
15→  targetStatus: string;
16→};
17→
18→/** Statuses that are at or beyond "done" -- no need to transition to done again */
19→const DONE_OR_BEYOND = new Set(["done", "completed"]);
20→
21→export function determineTaskStatusUpdates(input: {
22→  tasks: TaskStatusContext[];
23→  isDefaultBranch: boolean;
24→}): TaskStatusUpdate[] {
25→  if (input.isDefaultBranch) {
26→    // Default branch (merge to main): set eligible tasks to completed
27→    return input.tasks
28→      .filter((task) => task.currentStatus !== "completed")
29→      .map((task) => ({ taskId: task.taskId, targetStatus: "completed" }));
30→  }
31→
32→  // Feature branch: set eligible tasks to done
33→  return input.tasks
34→    .filter((task) => !DONE_OR_BEYOND.has(task.currentStatus))
35→    .map((task) => ({ taskId: task.taskId, targetStatus: "done" }));
36→}
