19→export async function executeCommitCheck(deps: {
20→  getLatestCommitMessage: GetLatestCommitMessage;
21→  postCommitCheck: PostCommitCheck;
22→}): Promise<void> {
23→  let commitMessage: string;
24→  try {
25→    commitMessage = deps.getLatestCommitMessage();
26→  } catch {
27→    return; // Not in a git repo
28→  }
29→
30→  if (!commitMessage) return;
31→
32→  try {
33→    await deps.postCommitCheck(commitMessage);
34→  } catch {
35→    // Fire-and-forget: never block git workflow
36→  }
37→}
