103→async function processCommit(input: {
104→  surreal: typeof import("surrealdb").Surreal.prototype;
105→  extractionModel: unknown;
106→  embeddingModel: unknown;
107→  embeddingDimension: number;
108→  extractionStoreThreshold: number;
109→  extractionModelId: string;
110→  workspaceRecord: RecordId<"workspace", string>;
111→  commit: CommitInput;
112→  workspaceName?: string;
113→  projectNames?: string[];
114→  autoLinkThreshold: number;
115→  isDefaultBranch: boolean;
116→  now: Date;
117→}): Promise<ProcessCommitResult> {
118→  const commitRecordId = randomUUID();
119→  const commitRecord = new RecordId("git_commit", commitRecordId);
120→
121→  // Resolve author
122→  const authorRecord = await findWorkspacePersonByName({
123→    surreal: input.surreal,
124→    workspaceRecord: input.workspaceRecord,
125→    personName: input.commit.authorName,
126→  });
127→
128→  // Create embedding for commit message
129→  const embedding = await createEmbedding(
130→    input.embeddingModel,
131→    input.embeddingDimension,
132→    input.commit.message,
133→  );
134→
135→  // Persist git_commit record
136→  await input.surreal.create(commitRecord).content({
137→    sha: input.commit.sha,
138→    repository: input.commit.repository,
139→    message: input.commit.message,
140→    authored_at: new Date(input.commit.authoredAt),
141→    ...(authorRecord ? { author: authorRecord } : {}),
142→    author_name: input.commit.authorName,
143→    url: input.commit.url,
144→    workspace: input.workspaceRecord,
145→    ...(embedding ? { embedding } : {}),
146→    created_at: input.now,
147→  });
148→
149→  logInfo("webhook.commit.created", "Created git_commit record", {
150→    sha: input.commit.sha,
151→    commitRecordId,
152→  });
153→
154→  const referencedTaskIds = extractReferencedTaskIds(input.commit.message);
155→  let linkedTaskCount = 0;
156→  let unresolvedTaskIds: string[] = [];
157→  let linkedTaskSummaries: Array<{ id: string; title: string }> = [];
158→  const taskStatusResults: TaskStatusUpdateResult[] = [];
159→
160→  if (referencedTaskIds.length > 0) {
161→    const taskRecords = referencedTaskIds.map((taskId) => new RecordId("task", taskId));
162→    const [taskRows] = await input.surreal
163→      .query<[Array<{ id: RecordId<"task", string>; title: string; status: string }> ]>(
164→        "SELECT id, title, status FROM task WHERE workspace = $workspace AND id IN $taskIds;",
165→        { workspace: input.workspaceRecord, taskIds: taskRecords },
166→      )
167→      .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string }>]>();
168→
169→    const foundTaskIds = new Set(taskRows.map((row) => row.id.id as string));
170→    unresolvedTaskIds = referencedTaskIds.filter((id) => !foundTaskIds.has(id));
171→
172→    for (const task of taskRows) {
173→      await input.surreal
174→        .relate(task.id, new RecordId("implemented_by", randomUUID()), commitRecord, {
175→          commit_sha: input.commit.sha,
176→          linked_at: input.now,
177→        })
178→        .output("after");
179→    }
180→
181→    linkedTaskCount = taskRows.length;
182→    linkedTaskSummaries = taskRows.map((row) => ({
183→      id: row.id.id as string,
184→      title: row.title,
185→    }));
186→
187→    // Determine and apply task status updates based on branch
188→    const statusUpdates = determineTaskStatusUpdates({
189→      tasks: taskRows.map((row) => ({
190→        taskId: row.id.id as string,
191→        currentStatus: row.status,
192→      })),
193→      isDefaultBranch: input.isDefaultBranch,
194→    });
195→
196→    for (const update of statusUpdates) {
197→      try {
198→        await updateTaskStatus({
199→          surreal: input.surreal,
200→          workspaceRecord: input.workspaceRecord,
201→          taskRecord: new RecordId("task", update.taskId),
202→          status: update.targetStatus,
203→        });
204→        taskStatusResults.push({ taskId: update.taskId, status: update.targetStatus });
205→        logInfo("webhook.commit.task_status", "Updated task status from push", {
206→          taskId: update.taskId,
207→          status: update.targetStatus,
208→          sha: input.commit.sha,
209→          isDefaultBranch: input.isDefaultBranch,
210→        });
211→      } catch (error) {
212→        logError("webhook.commit.task_status_failed", "Failed to update task status", error, {
213→          taskId: update.taskId,
214→          sha: input.commit.sha,
215→        });
216→      }
217→    }
218→  }
219→
220→  logInfo("webhook.commit.task_refs", "Processed explicit commit task references", {
221→    sha: input.commit.sha,
222→    referencedTaskCount: referencedTaskIds.length,
223→    linkedTaskCount,
224→    unresolvedTaskCount: unresolvedTaskIds.length,
225→  });
226→
227→  const extractionSourceText = buildCommitExtractionSourceText(
228→    input.commit.message,
229→    linkedTaskSummaries,
230→    unresolvedTaskIds,
231→  );
232→
233→  // Load workspace graph context for extraction
234→  const graphContext = await loadWorkspaceGraphContext(
235→    input.surreal,
236→    input.workspaceRecord,
237→    60,
238→  );
239→
240→  // Run extraction on commit message
241→  const extractionOutput = await extractStructuredGraph({
242→    extractionModel: input.extractionModel,
243→    conversationHistory: [],
244→    graphContext,
245→    sourceText: extractionSourceText,
246→    onboarding: false,
247→    workspaceName: input.workspaceName,
248→    projectNames: input.projectNames,
249→  });
250→
251→  // Persist extracted entities and relationships
252→  const persisted = await persistExtractionOutput({
253→    surreal: input.surreal,
254→    extractionModel: input.extractionModel,
255→    embeddingModel: input.embeddingModel,
256→    embeddingDimension: input.embeddingDimension,
257→    extractionModelId: input.extractionModelId,
258→    extractionStoreThreshold: input.extractionStoreThreshold,
259→    workspaceRecord: input.workspaceRecord,
260→    sourceRecord: commitRecord as SourceRecord,
261→    sourceKind: "git_commit",
262→    sourceLabel: `commit ${input.commit.sha.slice(0, 8)}`,
263→    promptText: extractionSourceText,
264→    output: extractionOutput,
265→    sourceCommitRecord: commitRecord,
266→    now: input.now,
267→  });
268→
269→  // Auto-link decisions based on confidence
270→  const autoLinkedDecisions: string[] = [];
271→  const observationsCreated: string[] = [];
272→  const actions = classifyDecisionLinks(persisted.entities, input.autoLinkThreshold);
273→
274→  for (const action of actions) {
275→    const decisionRecord = new RecordId("decision", action.entityId);
276→
277→    if (action.action === "auto_link") {
278→      await input.surreal
279→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
280→          commit_sha: input.commit.sha,
281→          linked_at: input.now,
282→        })
283→        .output("after");
284→
285→      autoLinkedDecisions.push(action.entityId);
286→      logInfo("webhook.commit.autolinked", "Auto-linked decision to commit", {
287→        decisionId: action.entityId,
288→        sha: input.commit.sha,
289→        confidence: action.confidence,
290→      });
291→    } else {
292→      const observation = await createObservation({
293→        surreal: input.surreal,
294→        workspaceRecord: input.workspaceRecord,
295→        text: `Commit ${input.commit.sha.slice(0, 8)} may implement decision "${action.text}" (confidence: ${(action.confidence * 100).toFixed(0)}%). Please confirm.`,
296→        severity: "info",
297→        sourceAgent: "git_webhook",
298→        now: input.now,
299→        relatedRecord: decisionRecord,
300→      });
301→
302→      observationsCreated.push(observation.id as string);
303→      logInfo("webhook.commit.observation", "Created confirmation observation", {
304→        decisionId: action.entityId,
305→        sha: input.commit.sha,
306→        confidence: action.confidence,
307→      });
308→    }
309→  }
310→
311→  return {
312→    commitRecord,
313→    entities: persisted.entities,
314→    relationships: persisted.relationships,
315→    autoLinkedDecisions,
316→    observationsCreated,
317→    taskStatusUpdates: taskStatusResults,
318→  };
319→}
320→
321→function buildCommitExtractionSourceText(
322→  message: string,
323→  linkedTasks: Array<{ id: string; title: string }>,
324→  unresolvedTaskIds: string[],
325→): string {
326→  if (linkedTasks.length === 0 && unresolvedTaskIds.length === 0) {
327→    return message;
328→  }
329→
330→  const lines = [message, "", "Explicit task references parsed from commit message:"];
331→  for (const task of linkedTasks) {
332→    lines.push(`- task:${task.id} (workspace task title: ${task.title})`);
333→  }
334→  for (const taskId of unresolvedTaskIds) {
335→    lines.push(`- task:${taskId} (not found in this workspace)`);
336→  }
337→  return lines.join("\n");
338→}
