 35→  // Step 2: .mcp.json
 36→  await setupMcpJson(gitRoot);
 37→
 38→  // Step 3: .claude/settings.json hooks
 39→  await setupClaudeHooks(gitRoot);
 40→
 41→  // Step 4: CLAUDE.md
 42→  await setupClaudeMd(gitRoot);
 43→
 44→  // Step 5: Commands
 45→  await setupCommands(gitRoot);
 46→
