345→
346→export function installGitHooks(gitRoot?: string): void {
347→  const root = gitRoot ?? findGitRoot(process.cwd());
348→  if (!root) {
349→    console.log("  No .git directory found — skipping git hook installation.");
350→    return;
351→  }
352→
353→  const hooksDir = join(root, ".git", "hooks");
354→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
355→
356→  const preCommitPath = join(hooksDir, "pre-commit");
357→  const postCommitPath = join(hooksDir, "post-commit");
358→  const preCommitScript = `#!/bin/sh
359→# Brain pre-commit hook: check for task completion and unlogged decisions
360→brain check-commit
361→`;
362→  const postCommitScript = `#!/bin/sh
363→# Brain post-commit hook: fire-and-forget commit-check
364→brain commit-check &
365→exit 0
366→`;
367→
368→  if (!existsSync(preCommitPath)) {
369→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
370→    console.log("✓ Git: pre-commit hook installed");
371→  } else {
372→    console.log("✓ Git: pre-commit hook already exists");
373→  }
374→
375→  // Remove legacy Brain post-commit hook, then install new one
376→  if (existsSync(postCommitPath)) {
377→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
378→    const isLegacyBrain =
379→      postCommitContent.includes("Brain post-commit hook") &&
380→      postCommitContent.includes("brain log-commit");
381→    const isCurrentBrain =
382→      postCommitContent.includes("Brain post-commit hook") &&
383→      postCommitContent.includes("brain commit-check");
384→    if (isLegacyBrain) {
385→      unlinkSync(postCommitPath);
386→      console.log("  Removed legacy Brain post-commit hook");
387→    } else if (isCurrentBrain) {
388→      console.log("✓ Git: post-commit hook already exists");
389→      return;
390→    } else {
391→      // Non-brain hook — leave it alone
392→      console.log("✓ Git: post-commit hook already exists (non-brain)");
393→      return;
394→    }
395→  }
396→
397→  writeFileSync(postCommitPath, postCommitScript, { mode: 0o755 });
398→  console.log("✓ Git: post-commit hook installed");
399→}
