 94→// --- Decision Linking Classification ---
 95→
 96→export type DecisionLinkAction =
 97→  | { action: "auto_link"; entityId: string; confidence: number }
 98→  | { action: "observe"; entityId: string; text: string; confidence: number };
 99→
100→export function classifyDecisionLinks(
101→  entities: Array<{ id: string; kind: EntityKind; text: string; confidence: number }>,
102→  autoLinkThreshold: number,
103→): DecisionLinkAction[] {
104→  const actions: DecisionLinkAction[] = [];
105→  for (const entity of entities) {
106→    if (entity.kind !== "decision") continue;
107→    if (entity.confidence >= autoLinkThreshold) {
108→      actions.push({ action: "auto_link", entityId: entity.id, confidence: entity.confidence });
109→    } else {
110→      actions.push({ action: "observe", entityId: entity.id, text: entity.text, confidence: entity.confidence });
111→    }
112→  }
113→  return actions;
114→}
