 16→function createUpdateTaskSpy(): { port: UpdateTaskPort; calls: Array<{ taskId: string; status: string }> } {
 17→  const calls: Array<{ taskId: string; status: string }> = [];
 18→  const port: UpdateTaskPort = async (taskId, status) => {
 19→    calls.push({ taskId, status });
 20→    return { task_id: taskId, status, updated: true };
 21→  };
 22→  return { port, calls };
 23→}
 24→
 25→function createTaskExistsPort(existingIds: Set<string>): TaskExistsPort {
 26→  return async (taskId) => existingIds.has(taskId);
 27→}
 28→
 29→describe("processCommitTaskRefs", () => {
 30→  it("Given a commit message with task:abc123, When processed, Then task abc123 is set to done", async () => {
