 33→
 34→    const result = await processCommitTaskRefs({
 35→      commitMessage: "Implement login flow\n\ntask:abc-1234",
 36→      updateTask,
 37→      taskExists,
 38→    });
 39→
 40→    expect(result.updatedTasks).toEqual([
 41→      { task_id: "abc-1234", status: "done", updated: true },
